#include <iostream>
#include <string>
using namespace std;
class Solution {
public:
bool isPangram(string s) {
    s.erase(remove(s.begin(), s.end(), ' '), s.end());
    for (int i = 0; i < 26; i++) {
        if (s.find('abcdefghijklmnopqrstuvwxyz'[i]) == string::npos) return false;
    }
    return true;
}
};
int main() {
    int t;
    cin >> t;
    while (t-- > 0) {
        string s;
        cin >> s;
        Solution obj;
        bool res = obj.isPangram(s);
        cout << (res ? "YES" : "NO") << endl;
    }
    return 0;
}
